solution.css:
.hero {
  position: relative;
  width: 100%;
  overflow: hidden;
  border-radius: 16px;
}

.hero-bg {
  width: 100%;
  aspect-ratio: 21 / 9;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
}

.hero-content {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  color: white;
  padding: 24px;
  background: rgba(0, 0, 0, 0.2);
}

.cta {
  display: inline-block;
  padding: 12px 24px;
  background: white;
  color: #667eea;
  text-decoration: none;
  border-radius: 8px;
  font-weight: 600;
  transition: transform 0.2s;
}

.cta:hover {
  transform: scale(1.05);
}

/* Mobile: change aspect ratio */
@media (max-width: 768px) {
  .hero-bg {
    aspect-ratio: 4 / 3;
  }
  .hero-content h1 {
    font-size: 1.5rem;
  }
}

/* Fallback for older browsers */
@supports not (aspect-ratio: 21 / 9) {
  .hero-bg {
    height: 0;
    padding-bottom: 42.85%; /* 9/21 * 100 = 42.85% */
  }
}

@supports not (aspect-ratio: 4 / 3) {
  @media (max-width: 768px) {
    .hero-bg {
      padding-bottom: 75%; /* 3/4 * 100 = 75% */
    }
  }
}
